-- Project builder tool definitions
INSERT OR IGNORE INTO tool_definitions (id, name, description, category, parameters_schema) VALUES
  ('tool_init_project', 'init_project', 'Crea workspace progetto con struttura cartelle, package.json/requirements.txt, .gitignore', 'dev', '{"type":"object","properties":{"path":{"type":"string","description":"Percorso dove creare il progetto"},"type":{"type":"string","enum":["node","react","nextjs","python","generic"],"default":"node","description":"Tipo di progetto"},"name":{"type":"string","description":"Nome del progetto"}},"required":["path","name"]}'),
  ('tool_install_deps', 'install_deps', 'Installa dipendenze del progetto (npm install, pip install, etc.)', 'dev', '{"type":"object","properties":{"path":{"type":"string","description":"Percorso root del progetto"},"packages":{"type":"array","items":{"type":"string"},"description":"Pacchetti specifici da installare"},"manager":{"type":"string","enum":["npm","pip","yarn","pnpm"],"description":"Package manager (auto-detect se omesso)"}},"required":["path"]}'),
  ('tool_run_dev_server', 'run_dev_server', 'Avvia dev server in background e ritorna URL localhost', 'dev', '{"type":"object","properties":{"path":{"type":"string","description":"Percorso root del progetto"},"command":{"type":"string","description":"Comando da eseguire (default: npm run dev)"},"port":{"type":"number","description":"Porta (default: auto)"}},"required":["path"]}'),
  ('tool_stop_dev_server', 'stop_dev_server', 'Ferma un dev server avviato in background', 'dev', '{"type":"object","properties":{"path":{"type":"string","description":"Percorso root del progetto"}},"required":["path"]}'),
  ('tool_run_tests', 'run_tests', 'Esegui test suite del progetto (npm test, pytest, etc.)', 'dev', '{"type":"object","properties":{"path":{"type":"string","description":"Percorso root del progetto"},"command":{"type":"string","description":"Comando test (default: npm test o pytest)"}},"required":["path"]}'),
  ('tool_git_init', 'git_init', 'Inizializza repository Git con .gitignore e opzionale primo commit', 'dev', '{"type":"object","properties":{"path":{"type":"string","description":"Percorso del progetto"},"initial_commit":{"type":"boolean","default":true,"description":"Creare commit iniziale"}},"required":["path"]}'),
  ('tool_list_project_files', 'list_project_files', 'Mostra albero file del progetto (ignora node_modules, .git, etc.)', 'dev', '{"type":"object","properties":{"path":{"type":"string","description":"Percorso root del progetto"},"depth":{"type":"number","default":4,"description":"Profondita massima"},"ignore":{"type":"array","items":{"type":"string"},"description":"Pattern da ignorare"}},"required":["path"]}');
